fix_patch:
diff --git c/include/simdjson/dom/element-inl.h i/include/simdjson/dom/element-inl.h
index 1f071da608..f4ce37302d 100644
--- c/include/simdjson/dom/element-inl.h
+++ i/include/simdjson/dom/element-inl.h
@@ -383,8 +383,15 @@ inline simdjson_result<element> element::at_pointer(std::string_view json_pointe
     case internal::tape_type::START_ARRAY:
       return array(tape).at_pointer(json_pointer);
     default: {
-      if(!json_pointer.empty()) { // a non-empty string is invalid on an atom
-        return INVALID_JSON_POINTER;
+      if(!json_pointer.empty()) { // a non-empty string cannot be resolved on an atom
+        if (json_pointer[0] != '/') { return INVALID_JSON_POINTER; }
+        for (size_t i = 0; i < json_pointer.size(); i++) {
+          if (json_pointer[i] == '~') {
+            if (i + 1 == json_pointer.size() || (json_pointer[i + 1] != '0' && json_pointer[i + 1] != '1')) { return INVALID_JSON_POINTER; }
+            i++;
+          }
+        }
+        return NO_SUCH_FIELD;
       }
       // an empty string means that we return the current node
       dom::element copy(*this);
